#!/usr/bin/env bash
# StreamVault — Self-hosted TorBox Stremio Addon
# Linux / macOS / WSL
#
# Usage:
#   curl -fsSL https://raw.githubusercontent.com/ray0189/streamvault/main/install.sh -o /tmp/sv.sh && bash /tmp/sv.sh

set -euo pipefail

R='\033[0;31m' G='\033[0;32m' Y='\033[1;33m'
C='\033[0;36m' W='\033[1;37m' DIM='\033[2m'
NC='\033[0m'   BOLD='\033[1m'
step() { echo -e "\n${C}▶${NC} ${BOLD}$*${NC}"; }
ok()   { echo -e "  ${G}✓${NC} $*"; }
warn() { echo -e "  ${Y}⚠${NC}  $*"; }
err()  { echo -e "\n  ${R}✗ $*${NC}\n"; exit 1; }
sep()  { echo -e "\n  ${DIM}──────────────────────────────────────────${NC}"; }
ask()  { echo -e "\n  ${W}$*${NC}"; }
lc()   { echo "$1" | tr '[:upper:]' '[:lower:]'; }

INSTALL_DIR="$HOME/streamvault"
CLI_BIN="/usr/local/bin/streamvault"
SVC="streamvault"
SUDO=""
[[ $EUID -ne 0 ]] && SUDO="sudo"

clear || true
echo -e "${C}${BOLD}"
echo '  ____  _                        _   _             _ _  '
echo ' / ___|| |_ _ __ ___  __ _ _ __ | | | | __ _ _   _| | |'
echo " \___ \| __| '__/ _ \/ _\` | '_ \| | | |/ _\` | | | | | |"
echo '  ___) | |_| | |  __/ (_| | | | | |_| | (_| | |_| | | |'
echo ' |____/ \__|_|  \___|\__,_|_| |_|\___/ \__,_|\__,_|_|_|'
echo -e "${NC}"
echo -e "  ${DIM}Self-hosted TorBox Stremio Addon — v1.2${NC}\n"

# ── OS detection ───────────────────────────────────────────────
step "Checking system"
OS="$(uname -s)"
IS_MAC=false; IS_WSL=false
[[ "$OS" == "Darwin" ]] && IS_MAC=true
[[ "$OS" == "Linux" ]] && grep -qi microsoft /proc/version 2>/dev/null && IS_WSL=true
[[ "$OS" != "Linux" && "$OS" != "Darwin" ]] && err "Linux, macOS, or WSL required"
$IS_MAC && ok "macOS" || { $IS_WSL && ok "WSL/Linux" || ok "Linux"; }

if $IS_MAC && ! command -v brew &>/dev/null; then
  echo -e "  ${DIM}Installing Homebrew...${NC}"
  /bin/bash -c "$(curl -fsSL https://raw.githubusercontent.com/Homebrew/install/HEAD/install.sh)"
  eval "$(/opt/homebrew/bin/brew shellenv)" 2>/dev/null || eval "$(/usr/local/bin/brew shellenv)" 2>/dev/null || true
fi

for cmd in curl git python3; do
  if command -v "$cmd" &>/dev/null; then ok "$cmd"
  elif $IS_MAC; then brew install "$cmd" && ok "$cmd installed"
  else err "$cmd required — sudo apt install $cmd"; fi
done

# ── Node.js ────────────────────────────────────────────────────
step "Node.js"
NODE_OK=false
command -v node &>/dev/null && node -e "process.exit(parseInt(process.version.slice(1))<18?1:0)" 2>/dev/null && NODE_OK=true || true
if $NODE_OK; then
  ok "Node.js $(node --version)"
else
  echo -e "  ${DIM}Installing Node.js v22...${NC}"
  if $IS_MAC; then
    brew install node@22 >/dev/null 2>&1 && brew link node@22 --force --overwrite >/dev/null 2>&1 || brew install node >/dev/null 2>&1
    export PATH="/opt/homebrew/opt/node@22/bin:/usr/local/opt/node@22/bin:$PATH"
  else
    curl -fsSL https://deb.nodesource.com/setup_22.x | $SUDO bash - >/dev/null
    $SUDO apt-get install -y nodejs >/dev/null
  fi
  ok "Node.js $(node --version)"
fi

# ── Redis ──────────────────────────────────────────────────────
step "Redis"
REDIS_OK=false
command -v redis-cli &>/dev/null && redis-cli ping 2>/dev/null | grep -q PONG && REDIS_OK=true || true
if $REDIS_OK; then
  ok "Redis running"
elif command -v docker &>/dev/null && docker ps 2>/dev/null | grep -q redis; then
  ok "Redis running (Docker)"
elif $IS_MAC; then
  brew install redis >/dev/null 2>&1
  brew services start redis >/dev/null 2>&1
  sleep 1 && ok "Redis started (Homebrew)"
elif command -v docker &>/dev/null; then
  docker run -d --name redis --restart always -p 6379:6379 redis:alpine >/dev/null 2>&1
  ok "Redis started (Docker)"
else
  $SUDO apt-get install -y redis-server >/dev/null 2>&1
  $SUDO systemctl enable --now redis-server >/dev/null 2>&1 || true
  ok "Redis installed"
fi

# ── Write source files ─────────────────────────────────────────
step "Writing source files"
mkdir -p "$INSTALL_DIR"/{src/{addon,api,cache,config,filters,profiles,scoring},data,dashboard,logs}

python3 << 'PYEOF_WRITE'
import os, base64
INSTALL_DIR = os.path.expanduser('~/streamvault')
files = {
  'src/server.js': '',
  'src/logger.js': '',
  'src/config/env.js': '',
  'src/config/defaults.js': '',
  'src/cache/store.js': '',
  'src/filters/quality.js': '',
  'src/scoring/rank.js': '',
  'src/profiles/store.js': '',
  'src/addon/manifest.js': '',
  'src/addon/router.js': '',
  'src/addon/streams.js': '',
  'src/api/torbox.js': '',
  'src/api/router.js': '',
  'dashboard/index.html': '',
}

for rel_path, encoded in files.items():
    content = base64.b64decode(encoded).decode('utf-8')
    full_path = os.path.join(INSTALL_DIR, rel_path)
    os.makedirs(os.path.dirname(full_path), exist_ok=True)
    with open(full_path, 'w', encoding='utf-8') as f:
        f.write(content)
print('  Source files written: ' + str(len(files)))

PYEOF_WRITE

cat > "$INSTALL_DIR/package.json" << 'PKGJSON'
{
  "name": "streamvault",
  "version": "1.2.0",
  "description": "Self-hosted TorBox Stremio addon",
  "main": "src/server.js",
  "scripts": { "start": "node src/server.js", "dev": "nodemon src/server.js" },
  "dependencies": {
    "axios": "^1.6.0",
    "chalk": "^4.1.2",
    "cors": "^2.8.5",
    "dotenv": "^16.3.1",
    "express": "^4.18.2",
    "express-rate-limit": "^7.1.5",
    "ioredis": "^5.3.2",
    "morgan": "^1.10.0",
    "node-cache": "^5.1.2",
    "uuid": "^9.0.0"
  },
  "devDependencies": { "nodemon": "^3.0.1" }
}
PKGJSON

cat > "$INSTALL_DIR/.gitignore" << 'GITIGNORE'
.env
data/
node_modules/
logs/
*.log
.DS_Store
GITIGNORE

ok "Source files written"

# ── Install dependencies ───────────────────────────────────────
step "Installing dependencies"
cd "$INSTALL_DIR"
npm install --no-fund --no-audit
ok "Dependencies installed"

# ══════════════════════════════════════════════════════════════
#  SETUP WIZARD
# ══════════════════════════════════════════════════════════════
sep
echo -e "\n  ${W}${BOLD}Setup Wizard${NC}"
echo -e "  ${DIM}Press Enter to accept defaults in [brackets]${NC}\n"

ask "TorBox API key — torbox.app/settings"
while true; do
  read -rp "  › " TORBOX_KEY
  [[ -n "$TORBOX_KEY" ]] && break
  echo -e "  ${R}Required${NC}"
done

ask "Admin password for the streamvault CLI (min 6 chars)"
while true; do
  read -rsp "  › " ADMIN_PASS; echo ""
  [[ ${#ADMIN_PASS} -ge 6 ]] && break
  echo -e "  ${R}Min 6 characters${NC}"
done

ask "Port [7000]"
read -rp "  › " PORT_IN
PORT="${PORT_IN:-7000}"

sep
echo -e "\n  ${W}${BOLD}Access method${NC}\n"
echo -e "  ${C}1${NC}  Cloudflare Tunnel  ${DIM}Public HTTPS, needs a domain${NC}"
echo -e "  ${C}2${NC}  Tailscale          ${DIM}Private, no domain needed${NC}"
echo -e "  ${C}3${NC}  Local only         ${DIM}Home/LAN only${NC}"
echo -e "  ${C}4${NC}  All three"
echo ""
while true; do
  read -rp "  › " ACCESS
  [[ "$ACCESS" =~ ^[1-4]$ ]] && break
  echo -e "  ${R}Enter 1-4${NC}"
done

CF_ENABLED=false; TS_ENABLED=false
CF_DOMAIN=""; CF_SUBDOMAIN="streamvault"; CF_TOKEN=""
TS_AUTH_KEY=""; TS_HOSTNAME="streamvault"

setup_cf() {
  sep; echo -e "\n  ${W}${BOLD}Cloudflare Tunnel${NC}"
  echo -e "  ${DIM}Token: dash.cloudflare.com/profile/api-tokens${NC}\n"
  ask "Cloudflare API token"
  while true; do read -rsp "  › " CF_TOKEN; echo ""; [[ -n "$CF_TOKEN" ]] && break; echo -e "  ${R}Required${NC}"; done
  ask "Your domain (e.g. yourdomain.com)"
  while true; do read -rp "  › " CF_DOMAIN; [[ -n "$CF_DOMAIN" ]] && break; echo -e "  ${R}Required${NC}"; done
  ask "Subdomain [streamvault]"
  read -rp "  › " CF_SUB_IN; CF_SUBDOMAIN="${CF_SUB_IN:-streamvault}"
  CF_ENABLED=true
}

setup_ts() {
  sep; echo -e "\n  ${W}${BOLD}Tailscale${NC}"
  echo -e "  ${DIM}Auth key: login.tailscale.com/admin/settings/keys${NC}\n"
  ask "Tailscale auth key"
  while true; do read -rsp "  › " TS_AUTH_KEY; echo ""; [[ -n "$TS_AUTH_KEY" ]] && break; echo -e "  ${R}Required${NC}"; done
  ask "Device hostname [streamvault]"
  read -rp "  › " TS_HOST_IN; TS_HOSTNAME="${TS_HOST_IN:-streamvault}"
  TS_ENABLED=true
}

case "$ACCESS" in
  1) setup_cf ;;
  2) setup_ts ;;
  3) true ;;
  4) setup_cf; setup_ts ;;
esac

sep; echo -e "\n  ${W}${BOLD}Quality defaults${NC}\n"
ask "Min resolution [1080p]  (480p/720p/1080p/2160p)"
read -rp "  › " RES_IN; MIN_RES="${RES_IN:-1080p}"
ask "Cached only? [Y/n]"
read -rp "  › " CACHED_IN
[[ "$(lc "${CACHED_IN:-y}")" == "n" ]] && CACHED_ONLY=false || CACHED_ONLY=true
ask "Prefer HEVC/x265? [Y/n]"
read -rp "  › " HEVC_IN
[[ "$(lc "${HEVC_IN:-y}")" == "n" ]] && PREFER_HEVC=false || PREFER_HEVC=true
ask "Prefer HDR/Dolby Vision? [Y/n]"
read -rp "  › " HDR_IN
[[ "$(lc "${HDR_IN:-y}")" == "n" ]] && PREFER_HDR=false || PREFER_HDR=true
ask "Prefer Atmos/TrueHD? [Y/n]"
read -rp "  › " ATMOS_IN
[[ "$(lc "${ATMOS_IN:-y}")" == "n" ]] && PREFER_ATMOS=false || PREFER_ATMOS=true
ask "Audio language [en]  (en/ar/fr/es/de/any)"
read -rp "  › " LANG_IN; PREF_LANG="${LANG_IN:-en}"
ask "Max file size GB [80]  (0=no limit)"
read -rp "  › " SIZE_IN; MAX_SIZE="${SIZE_IN:-80}"

# ── Write .env ────────────────────────────────────────────────
step "Writing config"
if $IS_MAC; then
  LOCAL_IP=$(ipconfig getifaddr en0 2>/dev/null || ipconfig getifaddr en1 2>/dev/null || echo "127.0.0.1")
else
  LOCAL_IP=$(hostname -I 2>/dev/null | awk '{print $1}' || echo "127.0.0.1")
fi

if [[ "$CF_ENABLED" == "true" && -n "$CF_DOMAIN" ]]; then
  PUBLIC_BASE_URL="https://${CF_SUBDOMAIN}.${CF_DOMAIN}"
elif [[ "$TS_ENABLED" == "true" ]]; then
  PUBLIC_BASE_URL="http://${TS_HOSTNAME}:${PORT}"
else
  PUBLIC_BASE_URL="http://${LOCAL_IP}:${PORT}"
fi

SECRET_KEY=$(python3 -c "import secrets; print(secrets.token_urlsafe(32))")

cat > "$INSTALL_DIR/.env" << ENVEOF
PORT=${PORT}
HOST=0.0.0.0
NODE_ENV=production
ADMIN_PASSWORD=${ADMIN_PASS}
TORBOX_API_KEY=${TORBOX_KEY}
TORBOX_API_URL=https://api.torbox.app/v1/api
SECRET_KEY=${SECRET_KEY}
NAS_LOCAL_IP=${LOCAL_IP}
TAILSCALE_HOST=${TS_HOSTNAME}
TS_ENABLED=${TS_ENABLED}
CF_ENABLED=${CF_ENABLED}
CF_DOMAIN=${CF_DOMAIN}
CF_SUBDOMAIN=${CF_SUBDOMAIN}
CF_TOKEN=${CF_TOKEN}
PUBLIC_BASE_URL=${PUBLIC_BASE_URL}
DEFAULT_MIN_QUALITY=${MIN_RES}
DEFAULT_CACHED_ONLY=${CACHED_ONLY}
DEFAULT_PREFER_HEVC=${PREFER_HEVC}
DEFAULT_PREFER_HDR=${PREFER_HDR}
DEFAULT_PREFER_ATMOS=${PREFER_ATMOS}
DEFAULT_LANGUAGE=${PREF_LANG}
DEFAULT_MAX_SIZE_GB=${MAX_SIZE}
STREAM_CACHE_TTL=300
META_CACHE_TTL=3600
ENVEOF
chmod 600 "$INSTALL_DIR/.env"
ok "Config saved"

# ── Cloudflare ────────────────────────────────────────────────
if [[ "$CF_ENABLED" == "true" ]]; then
  step "Cloudflare Tunnel"
  if ! command -v cloudflared &>/dev/null; then
    if $IS_MAC; then
      brew install cloudflared >/dev/null 2>&1
    else
      curl -fsSL https://pkg.cloudflare.com/cloudflare-main.gpg | $SUDO tee /usr/share/keyrings/cloudflare-main.gpg >/dev/null
      echo "deb [signed-by=/usr/share/keyrings/cloudflare-main.gpg] https://pkg.cloudflare.com/cloudflared any main" | $SUDO tee /etc/apt/sources.list.d/cloudflared.list >/dev/null
      $SUDO apt-get update -qq >/dev/null && $SUDO apt-get install -y cloudflared >/dev/null
    fi
    ok "cloudflared installed"
  else
    ok "cloudflared already installed"
  fi
  warn "Complete setup: cloudflared tunnel login && cloudflared tunnel create streamvault"
fi

# ── Tailscale ────────────────────────────────────────────────
if [[ "$TS_ENABLED" == "true" ]]; then
  step "Tailscale"
  if ! command -v tailscale &>/dev/null; then
    curl -fsSL https://tailscale.com/install.sh | sh >/dev/null
    ok "Tailscale installed"
  fi
  [[ -n "$TS_AUTH_KEY" ]] && $SUDO tailscale up --authkey="$TS_AUTH_KEY" --hostname="$TS_HOSTNAME" 2>/dev/null || true
  ok "Tailscale ready"
fi

# ── System service ────────────────────────────────────────────
step "System service"
NODE_BIN=$(command -v node)

if $IS_MAC; then
  python3 << 'PYEOF_PLIST'

import os
install_dir = os.path.expanduser('~/streamvault')
env_file = os.path.join(install_dir, '.env')
env_vars = {}
with open(env_file) as f:
    for line in f:
        line = line.strip()
        if line and not line.startswith('#') and '=' in line:
            k, _, v = line.partition('=')
            env_vars[k.strip()] = v.strip()

node_bin = os.popen('command -v node').read().strip()
env_dict = '\n'.join('    <key>' + k + '</key><string>' + v + '</string>' for k, v in env_vars.items())
log_path = install_dir + '/logs/streamvault.log'
plist_lines = [
    '<?xml version="1.0" encoding="UTF-8"?>',
    '<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">',
    '<plist version="1.0">',
    '<dict>',
    '  <key>Label</key><string>com.streamvault</string>',
    '  <key>ProgramArguments</key>',
    '  <array>',
    '    <string>' + node_bin + '</string>',
    '    <string>' + install_dir + '/src/server.js</string>',
    '  </array>',
    '  <key>WorkingDirectory</key><string>' + install_dir + '</string>',
    '  <key>EnvironmentVariables</key>',
    '  <dict>',
    env_dict,
    '  </dict>',
    '  <key>RunAtLoad</key><true/>',
    '  <key>KeepAlive</key><true/>',
    '  <key>StandardOutPath</key><string>' + log_path + '</string>',
    '  <key>StandardErrorPath</key><string>' + log_path + '</string>',
    '</dict>',
    '</plist>',
]
plist_path = os.path.expanduser('~/Library/LaunchAgents/com.streamvault.plist')
os.makedirs(os.path.dirname(plist_path), exist_ok=True)
with open(plist_path, 'w') as f:
    f.write('\n'.join(plist_lines))
print('  Plist written: ' + plist_path)

PYEOF_PLIST
  PLIST_PATH="$HOME/Library/LaunchAgents/com.streamvault.plist"
  launchctl unload "$PLIST_PATH" 2>/dev/null || true
  launchctl load -w "$PLIST_PATH"
  sleep 2
  curl -sf "http://localhost:${PORT}/health" >/dev/null \
    && ok "Service started (launchd)" \
    || warn "Starting — check: tail -f $INSTALL_DIR/logs/streamvault.log"
else
  $SUDO tee /etc/systemd/system/${SVC}.service >/dev/null << SVCEOF
[Unit]
Description=StreamVault — TorBox Stremio Addon
After=network.target
[Service]
Type=simple
User=$USER
WorkingDirectory=${INSTALL_DIR}
ExecStart=${NODE_BIN} src/server.js
Restart=always
RestartSec=5
EnvironmentFile=${INSTALL_DIR}/.env
[Install]
WantedBy=multi-user.target
SVCEOF
  $SUDO systemctl daemon-reload
  $SUDO systemctl enable ${SVC} >/dev/null
  $SUDO systemctl restart ${SVC}
  sleep 2
  $SUDO systemctl is-active --quiet ${SVC} \
    && ok "Service started (systemd)" \
    || err "Service failed — check: sudo journalctl -u streamvault -n 30"
fi

# ── CLI ───────────────────────────────────────────────────────
step "Installing CLI"
$SUDO tee "$CLI_BIN" >/dev/null << 'CLIEOF'
#!/usr/bin/env bash
INSTALL_DIR="$HOME/streamvault"
SVC="streamvault"
R='\033[0;31m' G='\033[0;32m' Y='\033[1;33m' C='\033[0;36m' W='\033[1;37m' DIM='\033[2m' NC='\033[0m' BOLD='\033[1m'
ok(){ echo -e "  ${G}✓${NC} $*"; }
err(){ echo -e "\n  ${R}✗ $*${NC}\n"; exit 1; }
sep(){ echo -e "\n  ${DIM}──────────────────────────────────────────${NC}"; }
ask(){ echo -e "\n  ${W}$*${NC}"; }
IS_MAC=false; [[ "$(uname -s)" == "Darwin" ]] && IS_MAC=true
[[ -f "$INSTALL_DIR/.env" ]] && source "$INSTALL_DIR/.env" || err "Config not found. Run installer first."
PORT="${PORT:-7000}"
API="http://localhost:${PORT}/api"
AH="x-admin-token: $ADMIN_PASSWORD"
_get(){ curl -sf "$API/$1" -H "$AH"; }
_post(){ curl -sf -X POST "$API/$1" -H "$AH" -H "Content-Type: application/json" -d "$2"; }
_del(){ curl -sf -X DELETE "$API/$1" -H "$AH"; }
_url(){
  local id="$1"
  if [[ -n "${PUBLIC_BASE_URL:-}" ]]; then echo "${PUBLIC_BASE_URL%/}/config/${id}/manifest.json"
  else
    local lip
    if $IS_MAC; then lip=$(ipconfig getifaddr en0 2>/dev/null || echo "localhost")
    else lip=$(hostname -I 2>/dev/null | awk '{print $1}' || echo "localhost"); fi
    echo "http://${lip}:${PORT}/config/${id}/manifest.json"
  fi
}
_find(){ _get "profiles" 2>/dev/null | python3 -c "
import sys,json
ps=json.load(sys.stdin); n='$1'.lower()
for p in ps:
    if p['name'].lower()==n or p['configId'].startswith(n):
        print(p['configId']); break
" 2>/dev/null; }
CMD="${1:-help}"; shift 2>/dev/null || true
case "$CMD" in
status)
  echo -e "\n  ${W}${BOLD}StreamVault Status${NC}"; sep
  if $IS_MAC; then
    launchctl list 2>/dev/null | grep -q com.streamvault && echo -e "  Service   ${G}● Running${NC}" || echo -e "  Service   ${R}● Stopped${NC}"
  else
    systemctl is-active --quiet $SVC 2>/dev/null && echo -e "  Service   ${G}● Running${NC}" || echo -e "  Service   ${R}● Stopped${NC}"
  fi
  curl -sf "http://localhost:${PORT}/health" >/dev/null && echo -e "  HTTP      ${G}● Online${NC}" || echo -e "  HTTP      ${R}● Unreachable${NC}"
  REDIS=$(redis-cli ping 2>/dev/null || docker exec redis redis-cli ping 2>/dev/null || echo FAIL)
  [[ "$REDIS" == "PONG" ]] && echo -e "  Redis     ${G}● Connected${NC}" || echo -e "  Redis     ${R}● Disconnected${NC}"
  echo "";;
logs)
  if $IS_MAC; then tail -f "$INSTALL_DIR/logs/streamvault.log"
  else sudo journalctl -u $SVC -f --no-pager; fi;;
restart)
  if $IS_MAC; then
    launchctl unload "$HOME/Library/LaunchAgents/com.streamvault.plist" 2>/dev/null
    launchctl load -w "$HOME/Library/LaunchAgents/com.streamvault.plist"
  else sudo systemctl restart $SVC; fi
  ok "Restarted";;
backup)
  DEST="$HOME/streamvault-backup-$(date +%Y-%m-%d_%H-%M).tar.gz"
  tar -czf "$DEST" -C "$HOME" streamvault --exclude='streamvault/node_modules' 2>/dev/null
  ok "Saved: $DEST";;
profile)
  SUB="${1:-}"; shift 2>/dev/null || true
  case "$SUB" in
  add)
    echo -e "\n  ${W}${BOLD}New Profile${NC}"; sep
    ask "Profile name"; read -rp "  › " P_NAME; [[ -z "$P_NAME" ]] && err "Name required"
    ask "Min resolution [${DEFAULT_MIN_QUALITY:-1080p}]"; read -rp "  › " P_RES; P_RES="${P_RES:-${DEFAULT_MIN_QUALITY:-1080p}}"
    ask "Cached only? [${DEFAULT_CACHED_ONLY:-true}]  (true/false)"; read -rp "  › " P_CACHED; P_CACHED="${P_CACHED:-${DEFAULT_CACHED_ONLY:-true}}"
    PAYLOAD=$(python3 -c "import json; print(json.dumps({'name':'$P_NAME','prefs':{'minQuality':'$P_RES','cachedOnly':$P_CACHED}}))")
    RESULT=$(_post "profiles" "$PAYLOAD" 2>/dev/null)
    ID=$(echo "$RESULT" | python3 -c "import sys,json; print(json.load(sys.stdin).get('configId',''))" 2>/dev/null)
    [[ -z "$ID" ]] && err "Failed — is StreamVault running? (streamvault status)"
    sep; echo -e "\n  ${G}${BOLD}✓ Profile created: $P_NAME${NC}\n"
    echo -e "  ${W}Manifest URL:${NC}\n  ${C}$(_url "$ID")${NC}"
    echo -e "\n  ${DIM}Add to Stremio: Search addons → paste URL → Install${NC}\n";;
  list)
    PROFS=$(_get "profiles" 2>/dev/null)
    COUNT=$(echo "$PROFS" | python3 -c "import sys,json; print(len(json.load(sys.stdin)))" 2>/dev/null || echo 0)
    echo -e "\n  ${W}${BOLD}Profiles ($COUNT)${NC}"; sep
    [[ "$COUNT" == "0" ]] && echo -e "\n  ${DIM}None — run: streamvault profile add${NC}\n" || \
    echo "$PROFS" | python3 -c "
import sys,json
for p in json.load(sys.stdin):
    pr=p.get('prefs',{})
    print('  ' + p['name'])
    print('    ' + p['configId'])
    print('    ' + str(pr.get('minQuality','—')) + ' · cached:' + str(pr.get('cachedOnly','—')))
    print()
";;
  url)
    [[ -z "${1:-}" ]] && err "Usage: streamvault profile url <name>"
    ID=$(_find "$1"); [[ -z "$ID" ]] && err "Profile not found"
    echo -e "\n  ${C}$(_url "$ID")${NC}\n";;
  del)
    [[ -z "${1:-}" ]] && err "Usage: streamvault profile del <name>"
    ID=$(_find "$1"); [[ -z "$ID" ]] && err "Profile not found"
    read -rp "  Delete '$1'? [y/N] " CONF
    [[ "$(echo "$CONF" | tr '[:upper:]' '[:lower:]')" != "y" ]] && echo "Cancelled" && exit 0
    _del "profiles/$ID" >/dev/null && ok "Deleted '$1'";;
  *) echo -e "\n  Usage: streamvault profile <add|list|url <name>|del <name>>\n";;
  esac;;
config)
  echo -e "\n  ${W}${BOLD}Config${NC}"; sep
  echo -e "  Port        ${C}${PORT}${NC}"
  echo -e "  Public URL  ${C}${PUBLIC_BASE_URL:-—}${NC}"
  echo -e "  TorBox      ${DIM}${TORBOX_API_KEY:0:8}…${NC}"
  echo -e "  Min quality ${C}${DEFAULT_MIN_QUALITY:-1080p}${NC}"
  echo -e "  Language    ${C}${DEFAULT_LANGUAGE:-en}${NC}"; echo "";;
help|--help|-h|"")
  echo -e "\n  ${W}${BOLD}streamvault${NC}\n"
  echo -e "  ${C}status${NC}                  Health check"
  echo -e "  ${C}logs${NC}                    Live logs"
  echo -e "  ${C}restart${NC}                 Restart service"
  echo -e "  ${C}backup${NC}                  Create backup"
  echo -e "  ${C}profile add${NC}             Create profile → manifest URL"
  echo -e "  ${C}profile list${NC}            List all profiles"
  echo -e "  ${C}profile url <name>${NC}      Print manifest URL"
  echo -e "  ${C}profile del <name>${NC}      Delete profile"
  echo -e "  ${C}config${NC}                  Show config"; echo "";;
*) echo -e "\n  ${R}Unknown: $CMD${NC} — run ${C}streamvault help${NC}\n"; exit 1;;
esac
CLIEOF
$SUDO chmod +x "$CLI_BIN"
ok "CLI installed"

# ── Done ──────────────────────────────────────────────────────
sep
echo -e "\n  ${G}${BOLD}✓ StreamVault installed${NC}\n"
echo -e "  ${W}Dashboard${NC}  ${C}${PUBLIC_BASE_URL}${NC}"
echo -e "\n  ${W}Next steps:${NC}"
echo -e "  ${DIM}1.${NC} ${C}streamvault profile add${NC}   — create a profile"
echo -e "  ${DIM}2.${NC} ${C}streamvault profile list${NC}  — get your manifest URL"
echo -e "  ${DIM}3.${NC} Paste URL into Stremio → Search addons → Install"
[[ "$CF_ENABLED" == "true" ]] && {
  echo -e "\n  ${Y}Complete Cloudflare setup:${NC}"
  echo -e "  ${C}cloudflared tunnel login${NC}"
  echo -e "  ${C}cloudflared tunnel create streamvault${NC}"
  echo -e "  ${C}sudo systemctl start cloudflared${NC}"
}
echo -e "\n  ${DIM}streamvault help — all commands${NC}\n"
